type EventMap = Record<string, unknown[]>;

type EventKey<T extends EventMap> = string & keyof T;
type WildcardKey = "*";

type Listener<T extends unknown[]> = (...args: T) => void;
type WildcardListener<T extends EventMap> = (event: EventKey<T>, ...args: T[EventKey<T>]) => void;

type EventListener<T extends EventMap, K extends keyof T> = K extends "*"
  ? WildcardListener<T>
  : K extends EventKey<T>
    ? Listener<T[K]>
    : never;

export class EventEmitter<Events extends EventMap> {
  private listeners = new Map<keyof Events | WildcardKey, Set<Listener<unknown[]>>>();
  private wildcardListeners = new Set<WildcardListener<Events>>();
  private listenerCounts = new Map<keyof Events | WildcardKey, number>();

  /**
   * Register an event listener for a specific event.
   */
  on<K extends EventKey<Events>>(event: K, listener: Listener<Events[K]>): this {
    return this.addListener(event, listener as Listener<unknown[]>);
  }

  /**
   * Register a wildcard listener that receives all events.
   */
  on(event: "*", listener: WildcardListener<Events>): this;

  on<K extends keyof Events>(event: K, listener: EventListener<Events, K>): this {
    if (event === "*") {
      this.wildcardListeners.add(listener as unknown as WildcardListener<Events>);
      this.incrementCount("*");
      return this;
    }
    return this.addListener(event as EventKey<Events>, listener as Listener<unknown[]>);
  }

  /**
   * Register a one-time listener for a specific event.
   */
  once<K extends EventKey<Events>>(event: K, listener: Listener<Events[K]>): this {
    const onceWrapper = ((...args: Events[K]) => {
      this.off(event, onceWrapper as Listener<Events[K]>);
      listener(...args);
    }) as Listener<unknown[]>;
    return this.addListener(event, onceWrapper);
  }

  /**
   * Register a one-time wildcard listener.
   */
  once(event: "*", listener: WildcardListener<Events>): this;

  once<K extends keyof Events>(event: K, listener: EventListener<Events, K>): this {
    if (event === "*") {
      const onceWrapper = ((ev: string, ...args: unknown[]) => {
        this.off(event as "*", onceWrapper as unknown as WildcardListener<Events>);
        (listener as unknown as WildcardListener<Events>)(ev as EventKey<Events>, ...args as Events[EventKey<Events>]);
      }) as unknown as WildcardListener<Events>;
      this.wildcardListeners.add(onceWrapper);
      this.incrementCount("*");
      return this;
    }
    return this.once(event as EventKey<Events>, listener as Listener<Events[EventKey<Events>]>);
  }

  /**
   * Remove an event listener.
   */
  off<K extends EventKey<Events>>(event: K, listener: Listener<Events[K]>): this {
    return this.removeListener(event, listener as Listener<unknown[]>);
  }

  /**
   * Remove a wildcard listener.
   */
  off(event: "*", listener: WildcardListener<Events>): this;

  off<K extends keyof Events>(event: K, listener: EventListener<Events, K>): this {
    if (event === "*") {
      if (this.wildcardListeners.delete(listener as unknown as WildcardListener<Events>)) {
        this.decrementCount("*");
      }
      return this;
    }
    return this.removeListener(event as EventKey<Events>, listener as Listener<unknown[]>);
  }

  /**
   * Emit an event with payload.
   */
  emit<K extends EventKey<Events>>(event: K, ...args: Events[K]): boolean {
    if (!this.listeners.has(event) && this.wildcardListeners.size === 0) {
      return false;
    }

    // Call wildcard listeners first
    if (this.wildcardListeners.size > 0) {
      for (const listener of this.wildcardListeners) {
        try {
          (listener as unknown as (...args: unknown[]) => void)(event, ...args);
        } catch {
          // Error handling: one listener failing doesn't stop others
        }
      }
    }

    // Call specific event listeners
    const eventListeners = this.listeners.get(event);
    if (eventListeners && eventListeners.size > 0) {
      for (const listener of eventListeners) {
        try {
          listener(...args);
        } catch {
          // Error handling: one listener failing doesn't stop others
        }
      }
    }

    return true;
  }

  /**
   * Remove all listeners.
   * Pass an event name to remove listeners only for that event.
   * Omit event to remove all listeners (including wildcards).
   */
  removeAll(): this;
  removeAll<K extends EventKey<Events>>(event: K): this;
  removeAll<K extends keyof Events>(event?: K): this {
    if (event === undefined) {
      this.listeners.clear();
      this.wildcardListeners.clear();
      this.listenerCounts.clear();
      return this;
    }

    if (event === "*") {
      this.wildcardListeners.clear();
      this.listenerCounts.delete("*");
      return this;
    }

    this.listeners.delete(event as EventKey<Events>);
    this.listenerCounts.delete(event);
    return this;
  }

  /**
   * Get the number of listeners for a given event (or "*" for wildcards).
   */
  listenerCount(event: keyof Events | WildcardKey): number {
    return this.listenerCounts.get(event) ?? 0;
  }

  /**
   * Get all event names that have at least one listener (excluding wildcards).
   */
  eventNames(): (keyof Events)[] {
    const names: (keyof Events)[] = [];
    for (const event of this.listeners.keys()) {
      if (event !== "*") {
        names.push(event);
      }
    }
    return names;
  }

  private addListener(event: EventKey<Events>, listener: Listener<unknown[]>): this {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, new Set());
    }
    this.listeners.get(event)!.add(listener);
    this.incrementCount(event);
    return this;
  }

  private removeListener(event: EventKey<Events>, listener: Listener<unknown[]>): this {
    const eventListeners = this.listeners.get(event);
    if (eventListeners && eventListeners.delete(listener)) {
      this.decrementCount(event);
      if (eventListeners.size === 0) {
        this.listeners.delete(event);
      }
    }
    return this;
  }

  private incrementCount(event: keyof Events | WildcardKey): void {
    this.listenerCounts.set(event, (this.listenerCounts.get(event) ?? 0) + 1);
  }

  private decrementCount(event: keyof Events | WildcardKey): void {
    const count = this.listenerCounts.get(event);
    if (count !== undefined) {
      if (count <= 1) {
        this.listenerCounts.delete(event);
      } else {
        this.listenerCounts.set(event, count - 1);
      }
    }
  }
}
